<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Snake</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }

  body {
    background: #1a1a2e;
    color: #e0e0e0;
    font-family: 'Segoe UI', system-ui, sans-serif;
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 100vh;
    overflow: hidden;
  }

  .container {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 16px;
  }

  h1 {
    font-size: 2rem;
    letter-spacing: 4px;
    text-transform: uppercase;
    color: #00ff88;
    text-shadow: 0 0 20px rgba(0, 255, 136, 0.4);
  }

  #score {
    font-size: 1.4rem;
    background: #16213e;
    padding: 8px 24px;
    border-radius: 8px;
    border: 1px solid #0f3460;
    min-width: 160px;
    text-align: center;
  }

  #score span {
    color: #00ff88;
    font-weight: bold;
  }

  #snake {
    border: 2px solid #0f3460;
    border-radius: 4px;
    background: #0a0a1a;
    box-shadow: 0 0 40px rgba(0, 255, 136, 0.08), inset 0 0 60px rgba(0,0,0,0.5);
    display: block;
  }

  .controls {
    display: flex;
    gap: 12px;
  }

  button {
    background: #16213e;
    color: #e0e0e0;
    border: 1px solid #0f3460;
    padding: 10px 28px;
    font-size: 1rem;
    border-radius: 6px;
    cursor: pointer;
    transition: all 0.15s ease;
    letter-spacing: 1px;
    text-transform: uppercase;
  }

  button:hover {
    background: #0f3460;
    border-color: #00ff88;
    color: #00ff88;
    box-shadow: 0 0 12px rgba(0, 255, 136, 0.2);
  }

  button:active {
    transform: scale(0.97);
  }

  .hint {
    font-size: 0.8rem;
    color: #555;
    margin-top: 4px;
  }
</style>
</head>
<body>
<div class="container">
  <h1>🐍 Snake</h1>
  <div id="score">Score: <span id="score-val">0</span></div>
  <canvas id="snake" width="500" height="500"></canvas>
  <div class="controls">
    <button id="start">Start</button>
    <button id="pause">Pause</button>
    <button id="reset">Reset</button>
  </div>
  <div class="hint">Use arrow keys to steer</div>
</div>

<script>
(function() {
  // ── Configuration ──
  const CELL = 25;            // pixels per cell
  const COLS = 20;            // grid width in cells (>=10)
  const ROWS = 20;            // grid height in cells (>=10)
  const TICK_MS = 120;        // auto-advance interval

  // ── DOM refs ──
  const canvas = document.getElementById('snake');
  const ctx = canvas.getContext('2d');
  const scoreEl = document.getElementById('score-val');
  const startBtn = document.getElementById('start');
  const pauseBtn = document.getElementById('pause');
  const resetBtn = document.getElementById('reset');

  // ── State ──
  let snakeArr;       // [{x,y}, ...] head first
  let foodPos;        // {x, y} or null
  let dir;            // current heading
  let nextDir;        // queued turn (applied on next tick)
  let aliveFlag;      // boolean
  let scoreVal;       // number
  let running;        // auto-advance interval id
  let paused;

  function init() {
    const startX = Math.floor(COLS / 2);
    const startY = Math.floor(ROWS / 2);
    snakeArr = [
      { x: startX, y: startY },
      { x: startX - 1, y: startY },
      { x: startX - 2, y: startY }
    ];
    dir = 'right';
    nextDir = 'right';
    aliveFlag = true;
    scoreVal = 0;
    paused = false;
    spawnFood();
    updateScoreUI();
    draw();
  }

  function spawnFood() {
    const occupied = new Set(snakeArr.map(s => s.x + ',' + s.y));
    let fx, fy, key;
    do {
      fx = Math.floor(Math.random() * COLS);
      fy = Math.floor(Math.random() * ROWS);
      key = fx + ',' + fy;
    } while (occupied.has(key));
    foodPos = { x: fx, y: fy };
  }

  function updateScoreUI() {
    scoreEl.textContent = scoreVal;
  }

  // ── Drawing ──
  function draw() {
    // Background grid
    ctx.fillStyle = '#0a0a1a';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Grid lines (subtle)
    ctx.strokeStyle = 'rgba(255,255,255,0.03)';
    ctx.lineWidth = 1;
    for (let x = 0; x <= COLS; x++) {
      ctx.beginPath();
      ctx.moveTo(x * CELL, 0);
      ctx.lineTo(x * CELL, ROWS * CELL);
      ctx.stroke();
    }
    for (let y = 0; y <= ROWS; y++) {
      ctx.beginPath();
      ctx.moveTo(0, y * CELL);
      ctx.lineTo(COLS * CELL, y * CELL);
      ctx.stroke();
    }

    // Food glow
    if (foodPos) {
      const fx = foodPos.x * CELL + CELL / 2;
      const fy = foodPos.y * CELL + CELL / 2;
      const grad = ctx.createRadialGradient(fx, fy, 2, fx, fy, CELL);
      grad.addColorStop(0, 'rgba(255, 60, 80, 0.9)');
      grad.addColorStop(1, 'rgba(255, 60, 80, 0)');
      ctx.fillStyle = grad;
      ctx.fillRect(foodPos.x * CELL - CELL / 2, foodPos.y * CELL - CELL / 2, CELL * 2, CELL * 2);

      // Food dot
      ctx.fillStyle = '#ff3c50';
      ctx.shadowColor = '#ff3c50';
      ctx.shadowBlur = 10;
      roundRect(foodPos.x * CELL + 3, foodPos.y * CELL + 3, CELL - 6, CELL - 6, 4);
      ctx.fill();
      ctx.shadowBlur = 0;
    }

    // Snake body (tail first so head draws on top)
    for (let i = snakeArr.length - 1; i >= 0; i--) {
      const seg = snakeArr[i];
      const t = i / Math.max(snakeArr.length - 1, 1);

      if (i === 0) {
        // Head
        ctx.fillStyle = '#00ff88';
        ctx.shadowColor = '#00ff88';
        ctx.shadowBlur = 8;
      } else {
        const g = Math.round(255 - t * 140);
        const b = Math.round(136 - t * 90);
        ctx.fillStyle = `rgb(${Math.round(0)}, ${g}, ${b})`;
        ctx.shadowBlur = 0;
      }

      roundRect(seg.x * CELL + 1, seg.y * CELL + 1, CELL - 2, CELL - 2, i === 0 ? 6 : 4);
      ctx.fill();
      ctx.shadowBlur = 0;

      // Eyes on head
      if (i === 0) {
        drawEyes(seg);
      }
    }

    // Game over overlay
    if (!aliveFlag) {
      ctx.fillStyle = 'rgba(0, 0, 0, 0.65)';
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.fillStyle = '#ff3c50';
      ctx.font = 'bold 42px "Segoe UI", system-ui, sans-serif';
      ctx.textAlign = 'center';
      ctx.fillText('GAME OVER', canvas.width / 2, canvas.height / 2 - 10);
      ctx.fillStyle = '#aaa';
      ctx.font = '18px "Segoe UI", system-ui, sans-serif';
      ctx.fillText('Score: ' + scoreVal, canvas.width / 2, canvas.height / 2 + 24);
    }

    // Paused overlay
    if (paused && aliveFlag) {
      ctx.fillStyle = 'rgba(0, 0, 0, 0.5)';
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.fillStyle = '#00ff88';
      ctx.font = 'bold 36px "Segoe UI", system-ui, sans-serif';
      ctx.textAlign = 'center';
      ctx.fillText('PAUSED', canvas.width / 2, canvas.height / 2 + 12);
    }
  }

  function roundRect(x, y, w, h, r) {
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.lineTo(x + w - r, y);
    ctx.quadraticCurveTo(x + w, y, x + w, y + r);
    ctx.lineTo(x + w, y + h - r);
    ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
    ctx.lineTo(x + r, y + h);
    ctx.quadraticCurveTo(x, y + h, x, y + h - r);
    ctx.lineTo(x, y + r);
    ctx.quadraticCurveTo(x, y, x + r, y);
    ctx.closePath();
  }

  function drawEyes(head) {
    const cx = head.x * CELL + CELL / 2;
    const cy = head.y * CELL + CELL / 2;
    let offsets;
    switch (dir) {
      case 'right': offsets = [[5, -5], [5, 5]]; break;
      case 'left':  offsets = [[-5, -5], [-5, 5]]; break;
      case 'up':    offsets = [[-5, -5], [5, -5]]; break;
      case 'down':  offsets = [[-5, 5], [5, 5]]; break;
    }
    ctx.fillStyle = '#fff';
    for (const [ox, oy] of offsets) {
      ctx.beginPath();
      ctx.arc(cx + ox, cy + oy, 3.5, 0, Math.PI * 2);
      ctx.fill();
    }
    ctx.fillStyle = '#111';
    for (const [ox, oy] of offsets) {
      ctx.beginPath();
      ctx.arc(cx + ox, cy + oy, 1.8, 0, Math.PI * 2);
      ctx.fill();
    }
  }

  // ── Game logic ──
  function tick() {
    if (!aliveFlag) return;

    // Apply queued direction (ignore 180° reversal — already handled in setDir)
    dir = nextDir;

    const head = snakeArr[0];
    let nx = head.x, ny = head.y;
    switch (dir) {
      case 'up':    ny--; break;
      case 'down':  ny++; break;
      case 'left':  nx--; break;
      case 'right': nx++; break;
    }

    // Wall collision → game over
    if (nx < 0 || nx >= COLS || ny < 0 || ny >= ROWS) {
      aliveFlag = false;
      draw();
      return;
    }

    // Self collision → game over (check against all segments except the tail,
    // which will move away — but only if not growing this tick)
    const ateFood = (foodPos && nx === foodPos.x && ny === foodPos.y);
    const checkLen = ateFood ? snakeArr.length : snakeArr.length - 1;

    for (let i = 0; i < checkLen; i++) {
      if (snakeArr[i].x === nx && snakeArr[i].y === ny) {
        aliveFlag = false;
        draw();
        return;
      }
    }

    // Move: prepend new head
    const newHead = { x: nx, y: ny };
    snakeArr.unshift(newHead);

    if (ateFood) {
      scoreVal++;
      updateScoreUI();
      spawnFood();
    } else {
      snakeArr.pop();
    }

    draw();
  }

  // ── Public API ──
  window.game = {
    get w() { return COLS; },
    get h() { return ROWS; },

    reset() {
      stopAutoAdvance();
      init();
    },

    tick() {
      tick();
    },

    setDir(d) {
      if (!aliveFlag) return;
      const opposites = { up: 'down', down: 'up', left: 'right', right: 'left' };
      // Ignore 180° reversal relative to current heading (dir, not nextDir)
      if (opposites[d] === dir) return;
      // Also ignore if same as already queued
      if (d === nextDir) return;
      nextDir = d;
    },

    setFood(x, y) {
      foodPos = { x: x, y: y };
      draw();
    },

    snake() {
      return snakeArr.map(s => [s.x, s.y]);
    },

    food() {
      if (!foodPos) return null;
      return [foodPos.x, foodPos.y];
    },

    alive() {
      return aliveFlag;
    },

    score() {
      return scoreVal;
    }
  };

  // ── Auto-advance (Start / Pause) ──
  function startAutoAdvance() {
    stopAutoAdvance();
    running = setInterval(tick, TICK_MS);
  }

  function stopAutoAdvance() {
    if (running !== undefined) {
      clearInterval(running);
      running = undefined;
    }
  }

  // ── Button handlers ──
  startBtn.addEventListener('click', () => {
    if (!aliveFlag) init();   // restart after game over
    paused = false;
    startAutoAdvance();
    draw();
  });

  pauseBtn.addEventListener('click', () => {
    if (!aliveFlag) return;
    paused = !paused;
    if (paused) {
      stopAutoAdvance();
    } else {
      startAutoAdvance();
    }
    draw();
  });

  resetBtn.addEventListener('click', () => {
    init();
  });

  // ── Keyboard input ──
  document.addEventListener('keydown', (e) => {
    const keyMap = {
      ArrowUp: 'up', ArrowDown: 'down', ArrowLeft: 'left', ArrowRight: 'right',
      w: 'up', W: 'up', s: 'down', S: 'down', a: 'left', A: 'left', d: 'right', D: 'right'
    };
    const d = keyMap[e.key];
    if (d) {
      e.preventDefault();
      window.game.setDir(d);
      // Auto-start on first keypress if not running
      if (!running && aliveFlag && !paused) {
        startAutoAdvance();
      }
    }
  });

  // ── Boot ──
  init();
})();
</script>
</body>
</html>
